sql:
SELECT network_name
FROM networks
ORDER BY network_name ASC;

SELECT subnet_name
FROM subnets
WHERE created_at = (SELECT MAX(created_at) FROM subnets);

SELECT subnet_name, description, hosts
FROM subnets
ORDER BY hosts DESC;

SELECT subnet_name, hosts
FROM subnets
ORDER BY hosts DESC;

SELECT network_id, COUNT(subnet_id) AS subnet_count
FROM subnets
GROUP BY network_id;

SELECT subnet_name, hosts AS population_size
FROM subnets
ORDER BY hosts DESC;

SELECT subnet_name
FROM subnets
WHERE hosts > 250;

SELECT COUNT(*) AS subnet_count
FROM subnets
WHERE network_id = (SELECT network_id FROM networks WHERE network_name = 'Oakland LAN');

SELECT s.subnet_name
FROM subnets s
JOIN ip_addresses i ON s.subnet_id = i.subnet_id;

SELECT subnet_name
FROM subnets
WHERE subnet_id = 1;

SELECT hosts AS host_count
FROM subnets
WHERE subnet_id = 1;
